  'sum(pt), sum(pt_nt), sum(sl_xuat), sum(tien_nt2), sum(thue_nt), sum(tien_nt_x), sum(tien2), sum(thue), sum(tien_xuat)'







      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  g._alterTitle = [null, [['%c', a[0], true], ['%s', g._itemName, true], ['%d1', formatDateView(a[1]), true], ['%d2', formatDateView(a[2]), true]]];
  var x = a[15];
  g._hiddenFields = [
    {Fields: 'gia2, tien2, thue, pt, gia, tien_xuat', Value: (x == '10' || x =='30')},
    {Fields: 'gia_nt2, tien_nt2, thue_nt, pt_nt, gia_nt, tien_nt_x, ma_nt, ty_gia', Value: (x == '10' || x == '20')}
  ];
}
